function lrError(m){$('.isi_warning_delete').text(m||'Leave Request gagal diproses.');$('.error_data_delete').fadeIn()}function lrFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),leave_type:$('#filter_leave_type').val(),status:$('#filter_status').val(),department_code:$('#filter_department_code').val(),keyword:$('#filter_keyword').val()}}function lrSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change')}function lrDays(){var a=new Date($('#start_date').val()),b=new Date($('#end_date').val()),d=1;if(!isNaN(a)&&!isNaN(b)&&b>=a)d=((b-a)/86400000)+1;if($('#start_half_day').val()==='PM')d-=.5;if($('#end_half_day').val()==='AM')d-=.5;d=Math.max(.5,d);var q=parseFloat($('#leave_quota_before').val()||0);$('#total_days_preview').val(d.toFixed(2));$('#leave_quota_after_preview').val(Math.max(0,q-d).toFixed(2))}function lrReset(t){$('#form_leave')[0].reset();$('#lr_id,#leave_no').val('');$('#employee_id,#department_code,#job_title_id,#handover_to_employee_id,#approver_employee_id,#hr_reviewer_employee_id').val(null).trigger('change');$('#leave_type,#start_half_day,#end_half_day,#workflow_status').val('').trigger('change');$('#leave_type').val('ANNUAL_LEAVE').trigger('change');$('#start_half_day,#end_half_day').val('FULL_DAY').trigger('change');$('#workflow_status').val('DRAFT').trigger('change');$('#request_date,#start_date,#end_date').val('<?=date('Y-m-d');?>');$('#leave_quota_before').val('12');lrDays();$('#modal_leave .modal-title').text(t||'Create Leave Request')}function lrAjax(s,a,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:$('#modal_leave'),ajax:{url:'<?=base_admin();?>modul/leave_request/leave_request_action.php?act='+a,type:'POST',dataType:'json',delay:250,data:function(x){return{term:x.term||'',exclude:$('#employee_id').val()||0,department_code:$('#department_code').val()||''}},processResults:function(d){return{results:d.results||[]}}}})}
$(function(){if($.fn.datepicker){$('.lr-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true})}if($.fn.select2){$('#filter_leave_type,#filter_status,#leave_type,#start_half_day,#end_half_day,#workflow_status').select2({width:'100%',allowClear:true});$('#filter_department_code').select2({width:'100%',allowClear:true,placeholder:'Semua Department',ajax:{url:'<?=base_admin();?>modul/leave_request/leave_request_action.php?act=department_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''}},processResults:function(d){return{results:d.results||[]}}}});lrAjax('#employee_id','employee_search','Pilih employee...');lrAjax('#department_code','department_search','Pilih department...');lrAjax('#job_title_id','job_title_search','Pilih job title...');lrAjax('#handover_to_employee_id','employee_search','Pilih handover...');lrAjax('#approver_employee_id','employee_search','Pilih approver...');lrAjax('#hr_reviewer_employee_id','employee_search','Pilih HR reviewer...')}var dt=$('#dtb_leave_request').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/leave_request/leave_request_data.php',type:'post',data:function(d){$.extend(d,lrFilters())},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_submitted').text(k.submitted||0);$('#kpi_approved').text(k.approved||0);$('#kpi_days').text(k.total_days||0);return j.data||[]},error:function(x){console.log(x.responseText);lrError('Data Leave Request gagal dimuat.')}}});$('#btn_open_lr').click(function(){lrReset('Create Leave Request');$('#modal_leave').modal({backdrop:'static',keyboard:false})});$('#btn_filter_lr').click(function(){dt.draw()});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw()});$('#btn_reset_lr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_leave_type,#filter_status,#filter_department_code').val(null).trigger('change');$('#filter_keyword').val('');dt.draw()});$('#btn_export_lr').click(function(){window.location='<?=base_admin();?>modul/leave_request/leave_request_action.php?act=export&'+$.param(lrFilters())});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide()});$('#start_date,#end_date,#start_half_day,#end_half_day,#leave_quota_before').on('keyup change',lrDays);$('#employee_id').on('change',function(){var id=$(this).val();if(!id)return;$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=employee_snapshot',{employee_id:id},function(r){if(r.status!=='good')return;var h=r.data;lrSet('#department_code',h.department_code,h.department_code+' - '+(h.nm_dept||''));lrSet('#job_title_id',h.job_title_id,(h.job_title_code||'')+' - '+(h.job_title_name||''));lrSet('#approver_employee_id',h.manager_employee_id,h.manager_no?h.manager_no+' - '+h.manager_name:'Manager ID '+h.manager_employee_id)},'json')});$('#form_leave').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Leave');if(r.status==='good'){$('#modal_leave').modal('hide');dt.draw(false);Swal.fire('Saved','Leave Request tersimpan. Total '+r.total_days+' hari.','success')}else lrError(r.error_message)},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Leave');lrError(x.responseText)})});$(document).on('click','.btn-lr-detail',function(){$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=detail',{id:$(this).data('id')},function(h){$('#lr_detail_body').html(h);$('#modal_lr_detail').modal('show')})});$(document).on('click','.btn-lr-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=get',{id:id},function(r){if(r.status!=='good'){lrError(r.error_message);return}lrReset('Edit Leave Request');var h=r.data||{};Object.keys(h).forEach(function(k){var e=$('#'+k);if(e.length&&!['employee_id','department_code','job_title_id','handover_to_employee_id','approver_employee_id','hr_reviewer_employee_id'].includes(k))e.val(h[k])});$('#lr_id').val(h.id);lrSet('#employee_id',h.employee_id,h.employee_text);lrSet('#department_code',h.department_code,h.department_text);lrSet('#job_title_id',h.job_title_id,h.job_title_text);lrSet('#handover_to_employee_id',h.handover_to_employee_id,h.handover_text);lrSet('#approver_employee_id',h.approver_employee_id,h.approver_text);lrSet('#hr_reviewer_employee_id',h.hr_reviewer_employee_id,h.hr_text);$('#leave_type,#start_half_day,#end_half_day,#workflow_status').trigger('change');lrDays();$('#modal_leave').modal({backdrop:'static',keyboard:false})},'json')});$(document).on('click','.btn-lr-decision',function(){var id=$(this).data('id'),no=$(this).data('no'),decision=$(this).data('decision');Swal.fire({title:decision+' leave?',text:no,input:'textarea',inputPlaceholder:'Catatan approval/return/reject',showCancelButton:true,confirmButtonText:decision}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=decision',{id:id,decision:decision,note:x.value||''},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Saved','Decision berhasil disimpan.','success')}else lrError(r.error_message)},'json')})});$(document).on('click','.btn-lr-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/leave_request/leave_request_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success')}else lrError(r.error_message)},'json')})})});
</script>
